  const activeDescendantId =
    totalItemCount > 0 ? `list-item-${selectedIndex}` : undefined;

  function renderFileItem(entry: FileEntry, idx: number): ReactNode {
    const sizeText = formatFileSize(entry.size);
    return (
      <ListItem
        key={entry.id}
