  if (isTauri) {
    try {
      const mod = await import(
        /* @vite-ignore */ '@tauri-apps/plugin-clipboard-manager'
      );
      await (mod as { writeText: (text: string) => Promise<void> }).writeText(
        text,
      );
      return;
